package com.tradepulseai.authservice.service;

import com.tradepulseai.authservice.dto.auth.LoginRequestDTO;
import com.tradepulseai.authservice.dto.auth.RegisterRequestDTO;
import com.tradepulseai.authservice.dto.credentials.ChangePasswordRequestDTO;
import com.tradepulseai.authservice.dto.credentials.CredentialsResponseDTO;
import com.tradepulseai.authservice.dto.credentials.UpdateCredentialsRequestDTO;
import com.tradepulseai.authservice.dto.credentials.UpdateCredentialsResponseDTO;
import com.tradepulseai.authservice.model.User;
import com.tradepulseai.authservice.util.JwtUtil;
import io.jsonwebtoken.JwtException;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.Optional;


@Service
public class AuthService {

    private final UserService userService;
    private final PasswordEncoder passwordEncoder;
    private final JwtUtil jwtUtil;

    public AuthService(UserService userService, PasswordEncoder passwordEncoder,  JwtUtil jwtUtil) {
        this.userService = userService;
        this.passwordEncoder = passwordEncoder;
        this.jwtUtil = jwtUtil;
    }

    public Optional<String> authenticate(LoginRequestDTO loginRequestDTO) {
        return userService
                .findByEmail(loginRequestDTO.getEmail())
                .filter(u -> passwordEncoder.matches(loginRequestDTO.getPassword(),
                        u.getPassword()))
                .map(u -> jwtUtil.generateToken(u.getEmail(), u.getRole(), u.getUserId()));
    }

    public boolean validateToken(String token){
        try{
            jwtUtil.validateToken(token);
            return true;

        } catch (JwtException e){
            return false;
        }
    }

    @Transactional
    public User register(RegisterRequestDTO registerRequestDTO) {
        String normalizedEmail = normalizeEmail(registerRequestDTO.getEmail());
        if (userService.existsByEmail(normalizedEmail)) {
            throw new IllegalArgumentException("An account with this email already exists");
        }
        // Encode password using BCryptPasswordEncoder bean
        String encodedPassword = passwordEncoder.encode(registerRequestDTO.getPassword());
        // Create user with role "User" as default
        return userService.createUser(normalizedEmail, encodedPassword, "User");
    }

    public CredentialsResponseDTO getCredentials(Long userId) {
        User user = userService.findById(userId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        return new CredentialsResponseDTO(user.getUserId(), user.getEmail());
    }

    public UpdateCredentialsResponseDTO updateCredentials(Long userId, UpdateCredentialsRequestDTO request) {
        User user = userService.findById(userId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        String requestedEmail = request.getEmail();
        String normalizedEmail = requestedEmail == null ? user.getEmail() : normalizeEmail(requestedEmail);
        boolean emailChanged = !normalizedEmail.equals(user.getEmail());

        if (emailChanged) {
            Optional<User> existing = userService.findByEmail(normalizedEmail);
            if (existing.isPresent() && !existing.get().getUserId().equals(userId)) {
                throw new IllegalArgumentException("An account with this email already exists");
            }
            user.setEmail(normalizedEmail);
        }

        if (!emailChanged) {
            throw new IllegalArgumentException("No credential changes provided");
        }

        User saved = userService.save(user);
        String refreshedToken = jwtUtil.generateToken(saved.getEmail(), saved.getRole(), saved.getUserId());
        return new UpdateCredentialsResponseDTO(saved.getUserId(), saved.getEmail(), refreshedToken);
    }

    public void changePassword(Long userId, ChangePasswordRequestDTO request) {
        User user = userService.findById(userId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        if (!passwordEncoder.matches(request.getCurrentPassword(), user.getPassword())) {
            throw new IllegalArgumentException("Current password is incorrect");
        }

        if (!request.getNewPassword().equals(request.getConfirmPassword())) {
            throw new IllegalArgumentException("New password and confirm password do not match");
        }

        if (passwordEncoder.matches(request.getNewPassword(), user.getPassword())) {
            throw new IllegalArgumentException("New password must be different from the current password");
        }

        user.setPassword(passwordEncoder.encode(request.getNewPassword()));
        userService.save(user);
    }


    public Long extractUserId(String token) {
        try {
            return jwtUtil.extractUserId(token);
        } catch (JwtException | IllegalArgumentException ex) {
            throw new JwtException("Invalid JWT");
        }
    }

    private String normalizeEmail(String email) {
        if (email == null || email.isBlank()) {
            throw new IllegalArgumentException("Email is required");
        }
        return email.trim().toLowerCase();
    }


}

package com.tradepulseai.authservice.service;

import com.tradepulseai.authservice.dto.auth.LoginRequestDTO;
import com.tradepulseai.authservice.dto.auth.RegisterRequestDTO;
import com.tradepulseai.authservice.dto.credentials.ChangePasswordRequestDTO;
import com.tradepulseai.authservice.dto.credentials.CredentialsResponseDTO;
import com.tradepulseai.authservice.dto.credentials.UpdateCredentialsRequestDTO;
import com.tradepulseai.authservice.dto.credentials.UpdateCredentialsResponseDTO;
import com.tradepulseai.authservice.model.User;
import com.tradepulseai.authservice.util.JwtUtil;
import io.jsonwebtoken.JwtException;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.Optional;


@Service
public class AuthService {

    private final UserService userService;
    private final PasswordEncoder passwordEncoder;
    private final JwtUtil jwtUtil;

    public AuthService(UserService userService, PasswordEncoder passwordEncoder,  JwtUtil jwtUtil) {
        this.userService = userService;
        this.passwordEncoder = passwordEncoder;
        this.jwtUtil = jwtUtil;
    }

    public Optional<String> authenticate(LoginRequestDTO loginRequestDTO) {
        return userService
                .findByEmail(loginRequestDTO.getEmail())
                .filter(u -> passwordEncoder.matches(loginRequestDTO.getPassword(),
                        u.getPassword()))
                .map(u -> jwtUtil.generateToken(u.getEmail(), u.getRole(), u.getUserId(), u.getFirstName(), u.getLastName()));
    }

    public boolean validateToken(String token){
        try{
            jwtUtil.validateToken(token);
            return true;

        } catch (JwtException e){
            return false;
        }
    }

    @Transactional
    public User register(RegisterRequestDTO registerRequestDTO) {
        String normalizedEmail = normalizeEmail(registerRequestDTO.getEmail());
        if (userService.existsByEmail(normalizedEmail)) {
            throw new IllegalArgumentException("An account with this email already exists");
        }
        // Encode password using BCryptPasswordEncoder bean
        String encodedPassword = passwordEncoder.encode(registerRequestDTO.getPassword());
        // Create user with role "User" as default
        return userService.createUser(normalizedEmail, encodedPassword, "User");
    }

    public CredentialsResponseDTO getCredentials(Long userId) {
        User user = userService.findById(userId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        return new CredentialsResponseDTO(user.getUserId(), user.getEmail());
    }

    public UpdateCredentialsResponseDTO updateCredentials(Long userId, UpdateCredentialsRequestDTO request) {
        User user = userService.findById(userId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        String requestedEmail = request.getEmail();
        String normalizedEmail = requestedEmail == null ? user.getEmail() : normalizeEmail(requestedEmail);
        boolean emailChanged = !normalizedEmail.equals(user.getEmail());

        if (emailChanged) {
            Optional<User> existing = userService.findByEmail(normalizedEmail);
            if (existing.isPresent() && !existing.get().getUserId().equals(userId)) {
                throw new IllegalArgumentException("An account with this email already exists");
            }
            user.setEmail(normalizedEmail);
        }

        if (!emailChanged) {
            throw new IllegalArgumentException("No credential changes provided");
        }

        User saved = userService.save(user);
        String refreshedToken = jwtUtil.generateToken(saved.getEmail(), saved.getRole(), saved.getUserId());
        return new UpdateCredentialsResponseDTO(saved.getUserId(), saved.getEmail(), refreshedToken);
    }

    public void changePassword(Long userId, ChangePasswordRequestDTO request) {
        User user = userService.findById(userId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        if (!passwordEncoder.matches(request.getCurrentPassword(), user.getPassword())) {
            throw new IllegalArgumentException("Current password is incorrect");
        }

        if (!request.getNewPassword().equals(request.getConfirmPassword())) {
            throw new IllegalArgumentException("New password and confirm password do not match");
        }

        if (passwordEncoder.matches(request.getNewPassword(), user.getPassword())) {
            throw new IllegalArgumentException("New password must be different from the current password");
        }

        user.setPassword(passwordEncoder.encode(request.getNewPassword()));
        userService.save(user);
    }


    public Long extractUserId(String token) {
        try {
            return jwtUtil.extractUserId(token);
        } catch (JwtException | IllegalArgumentException ex) {
            throw new JwtException("Invalid JWT");
        }
    }

    public String extractFirstName(String token) {
        try {
            return jwtUtil.extractFirstName(token);
        } catch (JwtException | IllegalArgumentException ex) {
            return "";
        }
    }

    public String extractLastName(String token) {
        try {
            return jwtUtil.extractLastName(token);
        } catch (JwtException | IllegalArgumentException ex) {
            return "";
        }
    }

    private String normalizeEmail(String email) {
        if (email == null || email.isBlank()) {
            throw new IllegalArgumentException("Email is required");
        }
        return email.trim().toLowerCase();
    }


}

package com.tradepulseai.authservice.util;

import io.jsonwebtoken.JwtException;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.Claims;
import io.jsonwebtoken.security.Keys;
import io.jsonwebtoken.security.SignatureException;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;

import javax.crypto.SecretKey;
import java.nio.charset.StandardCharsets;
import java.security.Key;
import java.util.Base64;
import java.util.Date;

@Component
public class JwtUtil {

    private final Key secretKey;

    public JwtUtil(@Value("${jwt.secret}") String secret){
        byte[] keyBytes = Base64.getDecoder().decode(secret.getBytes(StandardCharsets.UTF_8));

        this.secretKey = Keys.hmacShaKeyFor(keyBytes);
    }

    public String generateToken(String email, String role, Long userId){
        return Jwts.builder()
                .subject(email)
                .claim("role",role)
                .claim("userId", userId)
                .issuedAt(new Date())
                .expiration(new Date(System.currentTimeMillis() + 1000 * 60 * 60 * 10)) // 10 hours
                .signWith(secretKey)
                .compact();
    }

    public void validateToken(String token){
        try{
            parseClaims(token);

        } catch (SignatureException e) {
            throw new JwtException("Invalid JWT signature");
        } catch(JwtException e){
            throw new JwtException("Invalid JWT");
        }
    }

    public Claims parseClaims(String token) {
        return Jwts.parser()
                .verifyWith((SecretKey) secretKey)
                .build()
                .parseSignedClaims(token)
                .getPayload();
    }

    public Long extractUserId(String token) {
        Object raw = parseClaims(token).get("userId");
        if (raw instanceof Integer value) {
            return value.longValue();
        }
        if (raw instanceof Long value) {
            return value;
        }
        if (raw instanceof String value) {
            return Long.parseLong(value);
        }
        throw new JwtException("Invalid JWT userId claim");
    }
}

package com.tradepulseai.authservice.util;

import io.jsonwebtoken.JwtException;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.Claims;
import io.jsonwebtoken.security.Keys;
import io.jsonwebtoken.security.SignatureException;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;

import javax.crypto.SecretKey;
import java.nio.charset.StandardCharsets;
import java.security.Key;
import java.util.Base64;
import java.util.Date;

@Component
public class JwtUtil {

    private final Key secretKey;

    public JwtUtil(@Value("${jwt.secret}") String secret){
        byte[] keyBytes = Base64.getDecoder().decode(secret.getBytes(StandardCharsets.UTF_8));

        this.secretKey = Keys.hmacShaKeyFor(keyBytes);
    }

    public String generateToken(String email, String role, Long userId){
        return Jwts.builder()
                .subject(email)
                .claim("role",role)
                .claim("userId", userId)
                .issuedAt(new Date())
                .expiration(new Date(System.currentTimeMillis() + 1000 * 60 * 60 * 10)) // 10 hours
                .signWith(secretKey)
                .compact();
    }

    public String generateToken(String email, String role, Long userId, String firstName, String lastName){
        return Jwts.builder()
                .subject(email)
                .claim("role",role)
                .claim("userId", userId)
                .claim("firstName", firstName != null ? firstName : "")
                .claim("lastName", lastName != null ? lastName : "")
                .issuedAt(new Date())
                .expiration(new Date(System.currentTimeMillis() + 1000 * 60 * 60 * 10)) // 10 hours
                .signWith(secretKey)
                .compact();
    }

    public void validateToken(String token){
        try{
            parseClaims(token);

        } catch (SignatureException e) {
            throw new JwtException("Invalid JWT signature");
        } catch(JwtException e){
            throw new JwtException("Invalid JWT");
        }
    }

    public Claims parseClaims(String token) {
        return Jwts.parser()
                .verifyWith((SecretKey) secretKey)
                .build()
                .parseSignedClaims(token)
                .getPayload();
    }

    public Long extractUserId(String token) {
        Object raw = parseClaims(token).get("userId");
        if (raw instanceof Integer value) {
            return value.longValue();
        }
        if (raw instanceof Long value) {
            return value;
        }
        if (raw instanceof String value) {
            return Long.parseLong(value);
        }
        throw new JwtException("Invalid JWT userId claim");
    }

    public String extractFirstName(String token) {
        Object raw = parseClaims(token).get("firstName");
        return raw != null ? raw.toString() : "";
    }

    public String extractLastName(String token) {
        Object raw = parseClaims(token).get("lastName");
        return raw != null ? raw.toString() : "";
    }
}

package com.tradepulseai.notificationservice.service;

import com.tradepulseai.notificationservice.event.NotificationEvent;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.ObjectProvider;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.mail.SimpleMailMessage;
import org.springframework.mail.javamail.JavaMailSender;
import org.springframework.stereotype.Service;

import java.util.Map;

@Service
public class EmailNotificationService {

    private static final Logger log = LoggerFactory.getLogger(EmailNotificationService.class);

    private final JavaMailSender mailSender;
    private final String fromAddress;

    public EmailNotificationService(
            ObjectProvider<JavaMailSender> mailSenderProvider,
            @Value("${tradepulseai.mail.from:no-reply@tradepulseai.local}") String fromAddress
    ) {
        this.mailSender = mailSenderProvider.getIfAvailable();
        this.fromAddress = fromAddress;
    }

    public void sendNotification(NotificationEvent event, String toEmail) {
        if (mailSender == null) {
            log.error("Mail sender is not configured. Cannot send notification for eventType={}, userId={}",
                    event.getEventType(), event.getUserId());
            return;
        }

        if (toEmail == null || toEmail.isBlank()) {
            log.warn("No email address available for userId={}, skipping notification for eventType={}",
                    event.getUserId(), event.getEventType());
            return;
        }

        String subject = buildSubject(event);
        String body = buildBody(event);

        if (subject == null) {
            log.warn("Unknown eventType={}, skipping notification for userId={}", event.getEventType(), event.getUserId());
            return;
        }

        try {
            SimpleMailMessage message = new SimpleMailMessage();
            message.setFrom(fromAddress);
            message.setTo(toEmail);
            message.setSubject(subject);
            message.setText(body);
            mailSender.send(message);
            log.info("Notification email sent: eventType={}, userId={}, to={}", event.getEventType(), event.getUserId(), toEmail);
        } catch (Exception ex) {
            log.error("Failed to send notification email for eventType={}, userId={}: {}",
                    event.getEventType(), event.getUserId(), ex.getMessage(), ex);
        }
    }

    private String buildSubject(NotificationEvent event) {
        return switch (event.getEventType()) {
            case "ACCOUNT_CREATED"   -> "Welcome to TradePulseAI – Account Created";
            case "WALLET_DEPOSIT"    -> "TradePulseAI – Wallet Deposit Successful";
            case "WALLET_WITHDRAWAL" -> "TradePulseAI – Wallet Withdrawal Successful";
            case "STOCK_PURCHASED"   -> "TradePulseAI – Order Completed";
            case "STOCK_SOLD"        -> "TradePulseAI – Sell Order Settled";
            default -> null;
        };
    }

    private String buildBody(NotificationEvent event) {
        Map<String, Object> data = event.getData();

        return switch (event.getEventType()) {
            case "ACCOUNT_CREATED" -> {
                String firstName = getString(data, "firstName", "");
                String lastName = getString(data, "lastName", "");
                String fullName = (firstName + " " + lastName).trim();
                if (fullName.isEmpty()) {
                    fullName = "Valued Customer";
                }
                yield """
                        Hello %s,

                        Welcome to TradePulseAI! Your account has been successfully created.
                        You can now log in, add funds to your wallet, and start trading.

                        Happy trading!
                        — The TradePulseAI Team
                        """.formatted(fullName);
            }
            case "WALLET_DEPOSIT" -> {
                String transactionId = getString(data, "transactionId", "N/A");
                String amount  = getString(data, "amount", "0.00");
                String balance = getString(data, "newBalance", "0.00");
                yield """
                        Hi,

                        Your deposit of $%s has been successfully processed.
                        Transaction ID : %s
                        New Balance    : $%s

                        — The TradePulseAI Team
                        """.formatted(amount, transactionId, balance);
            }
            case "WALLET_WITHDRAWAL" -> {
                String transactionId = getString(data, "transactionId", "N/A");
                String amount  = getString(data, "amount", "0.00");
                String balance = getString(data, "newBalance", "0.00");
                yield """
                        Hi,

                        Your withdrawal of $%s has been successfully processed.
                        Transaction ID : %s
                        New Balance    : $%s

                        — The TradePulseAI Team
                        """.formatted(amount, transactionId, balance);
            }
            case "STOCK_PURCHASED" -> {
                String orderId = getString(data, "orderId", "N/A");
                String symbol   = getString(data, "symbol", getString(data, "stockId", "N/A"));
                String quantity = getString(data, "quantity", "0");
                String price    = getString(data, "price", "0.00");
                String total    = getString(data, "total", "0.00");
                yield """
                        Hi,

                        Your stock purchase order has been completed successfully.
                        Order ID  : %s
                        Stock     : %s
                        Quantity  : %s %s
                        Price     : $%s per share
                        Total     : $%s

                        Your portfolio has been updated.

                        — The TradePulseAI Team
                        """.formatted(orderId, symbol, quantity, shareUnit(quantity), price, total);
            }
            case "STOCK_SOLD" -> {
                String symbol   = getString(data, "symbol", "N/A");
                String quantity = getString(data, "quantity", "0");
                String price    = getString(data, "price", "0.00");
                String total    = getString(data, "total", "0.00");
                yield """
                        Hi,

                        Your sell order has been settled successfully.
                        Stock    : %s
                        Quantity : %s %s
                        Price    : $%s per share
                        Total    : $%s credited to your wallet

                        — The TradePulseAI Team
                        """.formatted(symbol, quantity, price, total);
            }
            default -> "A new activity has been recorded on your TradePulseAI account.";
        };
    }

    private String getString(Map<String, Object> data, String key, String defaultValue) {
        if (data == null) return defaultValue;
        Object value = data.get(key);
        return value != null ? value.toString() : defaultValue;
    }

    private String shareUnit(String quantity) {
        if (quantity == null || quantity.isBlank()) {
            return "shares";
        }

        try {
            return new java.math.BigDecimal(quantity).compareTo(java.math.BigDecimal.ONE) == 0 ? "share" : "shares";
        } catch (NumberFormatException exception) {
            return "shares";
        }
    }
}

